CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE departments(code varchar(8) PRIMARY KEY,name varchar(120) NOT NULL UNIQUE);
CREATE TABLE department_sections(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),department_code varchar(8) NOT NULL REFERENCES departments(code),section_code varchar(1) NOT NULL,UNIQUE(department_code,section_code),CHECK(section_code IN('A','B')));
CREATE TABLE academic_programs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),department_code varchar(8) NOT NULL REFERENCES departments(code),name varchar(160) NOT NULL,active boolean NOT NULL DEFAULT true,UNIQUE(department_code,name));
CREATE TABLE student_roster(id uuid PRIMARY KEY,student_id varchar(32) NOT NULL UNIQUE,legal_name varchar(120) NOT NULL,normalized_legal_name varchar(120) NOT NULL,department_code varchar(8) NOT NULL REFERENCES departments(code),section_code varchar(1) NOT NULL,current_year int NOT NULL,status varchar(16) NOT NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,CHECK(current_year BETWEEN 1 AND 4));
CREATE INDEX idx_roster_scope ON student_roster(department_code,section_code,current_year,status);
CREATE TABLE users(id uuid PRIMARY KEY,login_id varchar(32) NOT NULL UNIQUE,student_id varchar(32) UNIQUE,legal_name varchar(120),nickname varchar(30) NOT NULL,password_hash varchar(100) NOT NULL,role varchar(24) NOT NULL,status varchar(16) NOT NULL,department_code varchar(8) REFERENCES departments(code),section_code varchar(1),academic_year int,token_version int NOT NULL DEFAULT 0,ban_reason varchar(500),banned_by uuid,banned_at timestamptz,approved_by uuid,approved_at timestamptz,rejection_reason varchar(500),created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,version bigint NOT NULL DEFAULT 0,CHECK(role IN('SYSTEM_ADMIN','DEPARTMENT_ADMIN','MODERATOR','STUDENT')),CHECK(status IN('PENDING','ACTIVE','REJECTED','BANNED')));
CREATE INDEX idx_users_scope_status ON users(department_code,section_code,status);
CREATE TABLE verification_codes(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),code_hash varchar(100) NOT NULL UNIQUE,target_role varchar(24) NOT NULL,department_code varchar(8),section_code varchar(1),expires_at timestamptz NOT NULL,consumed_at timestamptz,consumed_by uuid REFERENCES users(id),revoked_at timestamptz,created_by uuid NOT NULL REFERENCES users(id),created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE refresh_tokens(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),user_id uuid NOT NULL REFERENCES users(id),token_hash varchar(64) NOT NULL UNIQUE,expires_at timestamptz NOT NULL,revoked_at timestamptz,created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX idx_refresh_user ON refresh_tokens(user_id);
CREATE TABLE courses(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),department_code varchar(8) NOT NULL REFERENCES departments(code),program_id uuid REFERENCES academic_programs(id),course_code varchar(24) NOT NULL,course_name varchar(160) NOT NULL,academic_year int NOT NULL,semester int NOT NULL,active boolean NOT NULL DEFAULT true,UNIQUE(department_code,course_code));
CREATE TABLE posts(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),author_id uuid NOT NULL REFERENCES users(id),body varchar(2000) NOT NULL,visibility varchar(24) NOT NULL,status varchar(16) NOT NULL,department_code varchar(8),section_code varchar(1),academic_year int,moderated_by uuid REFERENCES users(id),moderated_at timestamptz,rejection_reason varchar(500),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),version bigint NOT NULL DEFAULT 0);
CREATE INDEX idx_posts_feed ON posts(status,created_at DESC); CREATE INDEX idx_posts_scope ON posts(department_code,section_code,academic_year,status);
CREATE TABLE post_media(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),post_id uuid NOT NULL REFERENCES posts(id) ON DELETE CASCADE,storage_key varchar(500) NOT NULL,original_name varchar(255) NOT NULL,content_type varchar(100) NOT NULL,size_bytes bigint NOT NULL,width int,height int,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE post_audience_departments(post_id uuid REFERENCES posts(id) ON DELETE CASCADE,department_code varchar(8) REFERENCES departments(code),PRIMARY KEY(post_id,department_code));
CREATE TABLE post_reactions(post_id uuid REFERENCES posts(id) ON DELETE CASCADE,user_id uuid REFERENCES users(id),reaction varchar(8) NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),PRIMARY KEY(post_id,user_id),CHECK(reaction IN('LIKE','DISLIKE')));
CREATE TABLE comments(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),post_id uuid NOT NULL REFERENCES posts(id) ON DELETE CASCADE,author_id uuid NOT NULL REFERENCES users(id),body varchar(1000) NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),deleted_at timestamptz);
CREATE INDEX idx_comments_post ON comments(post_id,created_at);
CREATE TABLE question_papers(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),course_id uuid NOT NULL REFERENCES courses(id),academic_year int NOT NULL,semester int NOT NULL,exam_year int NOT NULL,title varchar(200) NOT NULL,storage_key varchar(500) NOT NULL,original_name varchar(255) NOT NULL,content_type varchar(100) NOT NULL,size_bytes bigint NOT NULL,uploaded_by uuid NOT NULL REFERENCES users(id),created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX idx_questions_search ON question_papers(course_id,exam_year,semester);
CREATE TABLE notices(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),department_code varchar(8) REFERENCES departments(code),title varchar(200) NOT NULL,body varchar(4000) NOT NULL,storage_key varchar(500),original_name varchar(255),content_type varchar(100),size_bytes bigint,published_by uuid NOT NULL REFERENCES users(id),published_at timestamptz NOT NULL DEFAULT now(),expires_at timestamptz,updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX idx_notices_scope ON notices(department_code,published_at DESC);
CREATE TABLE private_conversations(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),participant_one uuid NOT NULL REFERENCES users(id),participant_two uuid NOT NULL REFERENCES users(id),created_at timestamptz NOT NULL DEFAULT now(),CHECK(participant_one<>participant_two));
CREATE UNIQUE INDEX uq_conversation_pair ON private_conversations(LEAST(participant_one,participant_two),GREATEST(participant_one,participant_two));
CREATE TABLE private_messages(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),conversation_id uuid NOT NULL REFERENCES private_conversations(id),sender_id uuid NOT NULL REFERENCES users(id),client_message_id uuid NOT NULL,body varchar(2000) NOT NULL,sent_at timestamptz NOT NULL DEFAULT now(),UNIQUE(sender_id,client_message_id));
CREATE INDEX idx_messages_history ON private_messages(conversation_id,sent_at);
CREATE TABLE community_rooms(id uuid PRIMARY KEY,department_code varchar(8) NOT NULL REFERENCES departments(code),section_code varchar(1) NOT NULL,academic_year int NOT NULL,name varchar(120) NOT NULL,UNIQUE(department_code,section_code,academic_year));
CREATE TABLE community_messages(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),room_id uuid NOT NULL REFERENCES community_rooms(id),author_id uuid NOT NULL REFERENCES users(id),body varchar(3000) NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE community_polls(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),room_id uuid NOT NULL REFERENCES community_rooms(id),creator_id uuid NOT NULL REFERENCES users(id),question varchar(500) NOT NULL,status varchar(16) NOT NULL DEFAULT 'OPEN',closes_at timestamptz,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE community_poll_options(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),poll_id uuid NOT NULL REFERENCES community_polls(id) ON DELETE CASCADE,label varchar(200) NOT NULL,display_order int NOT NULL);
CREATE TABLE community_poll_votes(poll_id uuid NOT NULL REFERENCES community_polls(id) ON DELETE CASCADE,option_id uuid NOT NULL REFERENCES community_poll_options(id),user_id uuid NOT NULL REFERENCES users(id),created_at timestamptz NOT NULL DEFAULT now(),PRIMARY KEY(poll_id,user_id));
CREATE TABLE audit_events(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),actor_id uuid REFERENCES users(id),event_type varchar(80) NOT NULL,target_type varchar(80),target_id varchar(80),details jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX idx_audit_created ON audit_events(created_at DESC);
CREATE TABLE academic_rollovers(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),cycle_label varchar(80) NOT NULL UNIQUE,effective_date date NOT NULL,year_one_count int NOT NULL,year_two_count int NOT NULL,year_three_count int NOT NULL,graduated_count int NOT NULL,executed_by uuid NOT NULL REFERENCES users(id),executed_at timestamptz NOT NULL DEFAULT now());
